import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { environment } from '../../../environments/environment';

export interface Parent {
  id?: number;
  firstName: string;
  lastName: string;
  phone?: string;
}

export interface Student {
  id?: number;
  firstName: string;
  lastName: string;
  dateOfBirth?: string;
  gender?: string;
  address?: string;
  phone?: string;
  email?: string;
  nationality?: string;
  previousSchool?: string;
  medicalInfo?: string;
  emergencyContact?: string;
  emergencyPhone?: string;
  parent?: Parent;
  parentName?: string;
}

@Injectable({ providedIn: 'root' })
export class StudentService {
  private apiUrl = `${environment.apiUrl}/students`;

  constructor(private http: HttpClient) {}

  getAll(): Observable<Student[]> { return this.http.get<Student[]>(this.apiUrl); }
  getById(id: number): Observable<Student> { return this.http.get<Student>(`${this.apiUrl}/${id}`); }
  create(student: Student): Observable<Student> { return this.http.post<Student>(this.apiUrl, student); }
  update(id: number, student: Student): Observable<Student> { return this.http.put<Student>(`${this.apiUrl}/${id}`, student); }
  delete(id: number): Observable<void> { return this.http.delete<void>(`${this.apiUrl}/${id}`); }
}
